// ============================================
// worker-auth/src/index.js
// Internal Auth Service Worker
// ============================================

export default {
  async fetch(request, env, ctx) {
    return handleRequest(request, env, ctx);
  },
};

async function handleRequest(request, env, ctx) {
  const url = new URL(request.url);
  const path = url.pathname.replace("/auth", "") || "/";
  const method = request.method;

  // Verify internal request context
  const requestId = request.headers.get("X-Request-Id") || "direct-call";

  const router = new Router();

  router.post("/login", async (req) => {
    const body = await req.json();
    const { email, password } = body;

    if (!email || !password) {
      return jsonResponse({ error: "Email and password are required" }, 400);
    }

    // Simulate auth check (in production, use KV/D1/external auth)
    const token = await generateToken({ email, sub: crypto.randomUUID() }, env);

    // Notify other services about login event via notification service
    if (env.NOTIFICATION_SERVICE) {
      ctx.waitUntil(
        env.NOTIFICATION_SERVICE.fetch(
          new Request("http://internal.service/notifications/event", {
            method: "POST",
            headers: { "Content-Type": "application/json", "X-Request-Id": requestId },
            body: JSON.stringify({
              type: "user.login",
              email,
              timestamp: Date.now(),
              country: request.headers.get("X-Country"),
            }),
          })
        )
      );
    }

    return jsonResponse({
      success: true,
      token,
      expiresIn: 3600,
      requestId,
    });
  });

  router.post("/verify", async (req) => {
    const body = await req.json();
    const { token } = body;

    if (!token) {
      return jsonResponse({ error: "Token is required" }, 400);
    }

    const payload = await verifyToken(token, env);
    if (!payload) {
      return jsonResponse({ error: "Invalid or expired token" }, 401);
    }

    return jsonResponse({ valid: true, payload, requestId });
  });

  router.post("/refresh", async (req) => {
    const body = await req.json();
    const { token } = body;

    const payload = await verifyToken(token, env);
    if (!payload) {
      return jsonResponse({ error: "Invalid token" }, 401);
    }

    const newToken = await generateToken(payload, env);
    return jsonResponse({ success: true, token: newToken, expiresIn: 3600, requestId });
  });

  router.get("/health", () => {
    return jsonResponse({ service: "auth", status: "healthy", timestamp: new Date().toISOString() });
  });

  return router.handle(method, path, request);
}

async function generateToken(payload, env) {
  const header = btoa(JSON.stringify({ alg: "HS256", typ: "JWT" }));
  const now = Math.floor(Date.now() / 1000);
  const claims = btoa(
    JSON.stringify({
      ...payload,
      iat: now,
      exp: now + 3600,
    })
  );

  const key = await crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(env.JWT_SECRET || "default-secret-change-me"),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"]
  );

  const signature = await crypto.subtle.sign("HMAC", key, new TextEncoder().encode(`${header}.${claims}`));
  const sig = btoa(String.fromCharCode(...new Uint8Array(signature)));

  return `${header}.${claims}.${sig}`;
}

async function verifyToken(token, env) {
  try {
    const [header, claims, signature] = token.split(".");
    const key = await crypto.subtle.importKey(
      "raw",
      new TextEncoder().encode(env.JWT_SECRET || "default-secret-change-me"),
      { name: "HMAC", hash: "SHA-256" },
      false,
      ["verify"]
    );

    const sigBytes = Uint8Array.from(atob(signature), (c) => c.charCodeAt(0));
    const valid = await crypto.subtle.verify("HMAC", key, sigBytes, new TextEncoder().encode(`${header}.${claims}`));

    if (!valid) return null;

    const payload = JSON.parse(atob(claims));
    if (payload.exp && payload.exp < Math.floor(Date.now() / 1000)) return null;

    return payload;
  } catch {
    return null;
  }
}

