// ============================================
// worker-user/src/index.js
// Internal User Service Worker
// ============================================

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname.replace("/users", "") || "/";
    const method = request.method;
    const requestId = request.headers.get("X-Request-Id") || "direct-call";

    const router = new Router();

    // Middleware: Verify auth token for protected routes
    const authMiddleware = async (req) => {
      const authHeader = req.headers.get("Authorization");
      if (!authHeader?.startsWith("Bearer ")) {
        return jsonResponse({ error: "Authorization required" }, 401);
      }

      if (env.AUTH_SERVICE) {
        const authResp = await env.AUTH_SERVICE.fetch(
          new Request("http://internal.service/auth/verify", {
            method: "POST",
            headers: { "Content-Type": "application/json", "X-Request-Id": requestId },
            body: JSON.stringify({ token: authHeader.replace("Bearer ", "") }),
          })
        );
        const authData = await authResp.json();
        if (!authData.valid) {
          return jsonResponse({ error: "Invalid token" }, 401);
        }
        return authData.payload;
      }
      return null;
    };

    router.get("/", async (req) => {
      const authResult = await authMiddleware(req);
      if (authResult instanceof Response) return authResult;

      // Simulate fetching users from KV/D1
      const users = await getUsersFromStore(env);
      return jsonResponse({ users, total: users.length, requestId });
    });

    router.get("/stats", async () => {
      const users = await getUsersFromStore(env);
      return jsonResponse({
        totalUsers: users.length,
        activeUsers: users.filter((u) => u.active).length,
        newToday: users.filter((u) => {
          const created = new Date(u.createdAt);
          const today = new Date();
          return created.toDateString() === today.toDateString();
        }).length,
      });
    });

    router.get("/:id", async (req, params) => {
      const authResult = await authMiddleware(req);
      if (authResult instanceof Response) return authResult;

      const userId = params.id;
      const user = await getUserFromStore(env, userId);

      if (!user) {
        return jsonResponse({ error: "User not found" }, 404);
      }

      return jsonResponse({ user, requestId });
    });

    router.post("/", async (req) => {
      const body = await req.json();
      const { name, email } = body;

      if (!name || !email) {
        return jsonResponse({ error: "Name and email are required" }, 400);
      }

      const user = {
        id: crypto.randomUUID(),
        name,
        email,
        active: true,
        createdAt: new Date().toISOString(),
      };

      await saveUserToStore(env, user);

      // Notify about new user
      if (env.NOTIFICATION_SERVICE) {
        ctx.waitUntil(
          env.NOTIFICATION_SERVICE.fetch(
            new Request("http://internal.service/notifications/event", {
              method: "POST",
              headers: { "Content-Type": "application/json", "X-Request-Id": requestId },
              body: JSON.stringify({ type: "user.created", userId: user.id, email: user.email }),
            })
          )
        );
      }

      return jsonResponse({ user, requestId }, 201);
    });

    router.put("/:id", async (req, params) => {
      const authResult = await authMiddleware(req);
      if (authResult instanceof Response) return authResult;

      const userId = params.id;
      const updates = await req.json();
      const user = await getUserFromStore(env, userId);

      if (!user) {
        return jsonResponse({ error: "User not found" }, 404);
      }

      const updatedUser = { ...user, ...updates, id: userId, updatedAt: new Date().toISOString() };
      await saveUserToStore(env, updatedUser);

      return jsonResponse({ user: updatedUser, requestId });
    });

    router.delete("/:id", async (req, params) => {
      const authResult = await authMiddleware(req);
      if (authResult instanceof Response) return authResult;

      const userId = params.id;
      await deleteUserFromStore(env, userId);

      return jsonResponse({ deleted: true, userId, requestId });
    });

    router.get("/health", () => {
      return jsonResponse({ service: "user", status: "healthy", timestamp: new Date().toISOString() });
    });

    return router.handle(method, path, request);
  },
};

// Simulated data store using KV
async function getUsersFromStore(env) {
  if (env.USER_KV) {
    const list = await env.USER_KV.list({ prefix: "user:" });
    const users = await Promise.all(list.keys.map((key) => env.USER_KV.get(key.name, "json")));
    return users.filter(Boolean);
  }
  // Fallback demo data
  return [
    { id: "1", name: "Alice", email: "alice@example.com", active: true, createdAt: new Date().toISOString() },
    { id: "2", name: "Bob", email: "bob@example.com", active: true, createdAt: new Date().toISOString() },
  ];
}

async function getUserFromStore(env, id) {
  if (env.USER_KV) {
    return env.USER_KV.get(`user:${id}`, "json");
  }
  const users = await getUsersFromStore(env);
  return users.find((u) => u.id === id) || null;
}

async function saveUserToStore(env, user) {
  if (env.USER_KV) {
    await env.USER_KV.put(`user:${user.id}`, JSON.stringify(user));
  }
}

async function deleteUserFromStore(env, id) {
  if (env.USER_KV) {
    await env.USER_KV.delete(`user:${id}`);
  }
}

