// ============================================
// worker-product/src/index.js
// Internal Product Service Worker
// ============================================

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname.replace("/products", "") || "/";
    const method = request.method;
    const requestId = request.headers.get("X-Request-Id") || "direct-call";

    const router = new Router();

    router.get("/", async (req) => {
      const searchParams = new URL(req.url).searchParams;
      const category = searchParams.get("category");
      const limit = parseInt(searchParams.get("limit") || "50");
      const offset = parseInt(searchParams.get("offset") || "0");

      let products = await getProductsFromStore(env);

      if (category) {
        products = products.filter((p) => p.category === category);
      }

      const total = products.length;
      products = products.slice(offset, offset + limit);

      return jsonResponse({ products, total, limit, offset, requestId });
    });

    router.get("/stats", async () => {
      const products = await getProductsFromStore(env);
      const categories = {};
      products.forEach((p) => {
        categories[p.category] = (categories[p.category] || 0) + 1;
      });

      return jsonResponse({
        totalProducts: products.length,
        categories,
        averagePrice: products.length > 0 ? products.reduce((sum, p) => sum + p.price, 0) / products.length : 0,
        inStock: products.filter((p) => p.stock > 0).length,
      });
    });

    router.get("/search", async (req) => {
      const searchParams = new URL(req.url).searchParams;
      const query = searchParams.get("q")?.toLowerCase();

      if (!query) {
        return jsonResponse({ error: "Search query 'q' is required" }, 400);
      }

      const products = await getProductsFromStore(env);
      const results = products.filter(
        (p) => p.name.toLowerCase().includes(query) || p.description?.toLowerCase().includes(query) || p.category?.toLowerCase().includes(query)
      );

      return jsonResponse({ results, total: results.length, query, requestId });
    });

    router.get("/:id", async (req, params) => {
      const product = await getProductFromStore(env, params.id);
      if (!product) {
        return jsonResponse({ error: "Product not found" }, 404);
      }
      return jsonResponse({ product, requestId });
    });

    router.post("/", async (req) => {
      const body = await req.json();
      const { name, price, category, description, stock } = body;

      if (!name || price === undefined) {
        return jsonResponse({ error: "Name and price are required" }, 400);
      }

      const product = {
        id: crypto.randomUUID(),
        name,
        price: parseFloat(price),
        category: category || "uncategorized",
        description: description || "",
        stock: stock || 0,
        createdAt: new Date().toISOString(),
      };

      await saveProductToStore(env, product);

      return jsonResponse({ product, requestId }, 201);
    });

    router.put("/:id", async (req, params) => {
      const product = await getProductFromStore(env, params.id);
      if (!product) {
        return jsonResponse({ error: "Product not found" }, 404);
      }

      const updates = await req.json();
      const updatedProduct = { ...product, ...updates, id: params.id, updatedAt: new Date().toISOString() };

      if (updatedProduct.price !== undefined) {
        updatedProduct.price = parseFloat(updatedProduct.price);
      }

      await saveProductToStore(env, updatedProduct);

      // If stock changed to 0, notify
      if (updatedProduct.stock === 0 && product.stock > 0 && env.NOTIFICATION_SERVICE) {
        ctx.waitUntil(
          env.NOTIFICATION_SERVICE.fetch(
            new Request("http://internal.service/notifications/event", {
              method: "POST",
              headers: { "Content-Type": "application/json", "X-Request-Id": requestId },
              body: JSON.stringify({ type: "product.out_of_stock", productId: params.id, productName: updatedProduct.name }),
            })
          )
        );
      }

      return jsonResponse({ product: updatedProduct, requestId });
    });

    router.post("/:id/reserve", async (req, params) => {
      const product = await getProductFromStore(env, params.id);
      if (!product) {
        return jsonResponse({ error: "Product not found" }, 404);
      }

      const { quantity } = await req.json();
      if (!quantity || quantity <= 0) {
        return jsonResponse({ error: "Valid quantity is required" }, 400);
      }

      if (product.stock < quantity) {
        return jsonResponse({ error: "Insufficient stock", available: product.stock }, 409);
      }

      product.stock -= quantity;
      product.updatedAt = new Date().toISOString();
      await saveProductToStore(env, product);

      return jsonResponse({ reserved: true, productId: params.id, quantity, remainingStock: product.stock, requestId });
    });

    router.delete("/:id", async (req, params) => {
      await deleteProductFromStore(env, params.id);
      return jsonResponse({ deleted: true, productId: params.id, requestId });
    });

    router.get("/health", () => {
      return jsonResponse({ service: "product", status: "healthy", timestamp: new Date().toISOString() });
    });

    return router.handle(method, path, request);
  },
};

async function getProductsFromStore(env) {
  if (env.PRODUCT_KV) {
    const list = await env.PRODUCT_KV.list({ prefix: "product:" });
    const products = await Promise.all(list.keys.map((key) => env.PRODUCT_KV.get(key.name, "json")));
    return products.filter(Boolean);
  }
  return [
    { id: "p1", name: "Widget A", price: 29.99, category: "widgets", stock: 100, createdAt: new Date().toISOString() },
    { id: "p2", name: "Gadget B", price: 49.99, category: "gadgets", stock: 50, createdAt: new Date().toISOString() },
    { id: "p3", name: "Widget C", price: 19.99, category: "widgets", stock: 0, createdAt: new Date().toISOString() },
  ];
}

async function getProductFromStore(env, id) {
  if (env.PRODUCT_KV) {
    return env.PRODUCT_KV.get(`product:${id}`, "json");
  }
  const products = await getProductsFromStore(env);
  return products.find((p) => p.id === id) || null;
}

async function saveProductToStore(env, product) {
  if (env.PRODUCT_KV) {
    await env.PRODUCT_KV.put(`product:${product.id}`, JSON.stringify(product));
  }
}

async function deleteProductFromStore(env, id) {
  if (env.PRODUCT_KV) {
    await env.PRODUCT_KV.delete(`product:${id}`);
  }
}

