// ============================================
// worker-order/src/index.js
// Internal Order Service Worker
// ============================================

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname.replace("/orders", "") || "/";
    const method = request.method;
    const requestId = request.headers.get("X-Request-Id") || "direct-call";

    const router = new Router();

    // Auth middleware using auth service binding
    const requireAuth = async (req) => {
      const authHeader = req.headers.get("Authorization");
      if (!authHeader?.startsWith("Bearer ") || !env.AUTH_SERVICE) {
        return null;
      }
      const resp = await env.AUTH_SERVICE.fetch(
        new Request("http://internal.service/auth/verify", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ token: authHeader.replace("Bearer ", "") }),
        })
      );
      const data = await resp.json();
      return data.valid ? data.payload : null;
    };

    router.get("/", async (req) => {
      const user = await requireAuth(req);
      if (!user) return jsonResponse({ error: "Unauthorized" }, 401);

      const orders = await getOrdersFromStore(env, user.sub);
      return jsonResponse({ orders, total: orders.length, requestId });
    });

    router.get("/stats", async () => {
      const allOrders = await getAllOrdersFromStore(env);
      const statusCounts = {};
      let totalRevenue = 0;

      allOrders.forEach((o) => {
        statusCounts[o.status] = (statusCounts[o.status] || 0) + 1;
        if (o.status === "completed") totalRevenue += o.total;
      });

      return jsonResponse({
        totalOrders: allOrders.length,
        statusBreakdown: statusCounts,
        totalRevenue,
        averageOrderValue: allOrders.length > 0 ? totalRevenue / allOrders.filter((o) => o.status === "completed").length : 0,
      });
    });

    router.get("/:id", async (req, params) => {
      const user = await requireAuth(req);
      if (!user) return jsonResponse({ error: "Unauthorized" }, 401);

      const order = await getOrderFromStore(env, params.id);
      if (!order) return jsonResponse({ error: "Order not found" }, 404);
      if (order.userId !== user.sub) return jsonResponse({ error: "Forbidden" }, 403);

      return jsonResponse({ order, requestId });
    });

    router.post("/", async (req) => {
      const user = await requireAuth(req);
      if (!user) return jsonResponse({ error: "Unauthorized" }, 401);

      const body = await req.json();
      const { items } = body;

      if (!items || !Array.isArray(items) || items.length === 0) {
        return jsonResponse({ error: "Items array is required" }, 400);
      }

      // Validate and reserve products via product service
      const reservationResults = [];
      if (env.PRODUCT_SERVICE) {
        for (const item of items) {
          const reserveResp = await env.PRODUCT_SERVICE.fetch(
            new Request(`http://internal.service/products/${item.productId}/reserve`, {
              method: "POST",
              headers: { "Content-Type": "application/json", "X-Request-Id": requestId },
              body: JSON.stringify({ quantity: item.quantity }),
            })
          );
          const reserveData = await reserveResp.json();

          if (!reserveResp.ok) {
            // Rollback would happen here in production
            return jsonResponse(
              {
                error: "Failed to reserve product",
                productId: item.productId,
                details: reserveData,
              },
              reserveResp.status
            );
          }
          reservationResults.push(reserveData);
        }
      }

      // Fetch product details for pricing
      let total = 0;
      const orderItems = [];

      for (const item of items) {
        let productData = { price: item.price || 0, name: item.name || "Unknown" };

        if (env.PRODUCT_SERVICE) {
          const productResp = await env.PRODUCT_SERVICE.fetch(
            new Request(`http://internal.service/products/${item.productId}`, {
              headers: { "X-Request-Id": requestId },
            })
          );
          if (productResp.ok) {
            const data = await productResp.json();
            productData = data.product;
          }
        }

        const lineTotal = productData.price * item.quantity;
        total += lineTotal;

        orderItems.push({
          productId: item.productId,
          productName: productData.name,
          quantity: item.quantity,
          unitPrice: productData.price,
          lineTotal,
        });
      }

      const order = {
        id: crypto.randomUUID(),
        userId: user.sub,
        userEmail: user.email,
        items: orderItems,
        total,
        status: "pending",
        createdAt: new Date().toISOString(),
      };

      await saveOrderToStore(env, order);

      // Send order confirmation notification
      if (env.NOTIFICATION_SERVICE) {
        ctx.waitUntil(
          env.NOTIFICATION_SERVICE.fetch(
            new Request("http://internal.service/notifications/event", {
              method: "POST",
              headers: { "Content-Type": "application/json", "X-Request-Id": requestId },
              body: JSON.stringify({
                type: "order.created",
                orderId: order.id,
                userId: user.sub,
                email: user.email,
                total: order.total,
                itemCount: order.items.length,
              }),
            })
          )
        );
      }

      return jsonResponse({ order, requestId }, 201);
    });

    router.put("/:id/status", async (req, params) => {
      const { status } = await req.json();
      const validStatuses = ["pending", "processing", "shipped", "completed", "cancelled"];

      if (!validStatuses.includes(status)) {
        return jsonResponse({ error: `Invalid status. Must be one of: ${validStatuses.join(", ")}` }, 400);
      }

      const order = await getOrderFromStore(env, params.id);
      if (!order) return jsonResponse({ error: "Order not found" }, 404);

      const previousStatus = order.status;
      order.status = status;
      order.updatedAt = new Date().toISOString();
      order.statusHistory = order.statusHistory || [];
      order.statusHistory.push({ from: previousStatus, to: status, at: order.updatedAt });

      await saveOrderToStore(env, order);

      // Notify about status change
      if (env.NOTIFICATION_SERVICE) {
        ctx.waitUntil(
          env.NOTIFICATION_SERVICE.fetch(
            new Request("http://internal.service/notifications/event", {
              method: "POST",
              headers: { "Content-Type": "application/json", "X-Request-Id": requestId },
              body: JSON.stringify({
                type: "order.status_changed",
                orderId: order.id,
                userId: order.userId,
                email: order.userEmail,
                previousStatus,
                newStatus: status,
              }),
            })
          )
        );
      }

      return jsonResponse({ order, requestId });
    });

    router.get("/health", () => {
      return jsonResponse({ service: "order", status: "healthy", timestamp: new Date().toISOString() });
    });

    return router.handle(method, path, request);
  },
};

async function getOrdersFromStore(env, userId) {
  const allOrders = await getAllOrdersFromStore(env);
  return allOrders.filter((o) => o.userId === userId);
}

async function getAllOrdersFromStore(env) {
  if (env.ORDER_KV) {
    const list = await env.ORDER_KV.list({ prefix: "order:" });
    const orders = await Promise.all(list.keys.map((key) => env.ORDER_KV.get(key.name, "json")));
    return orders.filter(Boolean);
  }
  return [];
}

async function getOrderFromStore(env, id) {
  if (env.ORDER_KV) {
    return env.ORDER_KV.get(`order:${id}`, "json");
  }
  return null;
}

async function saveOrderToStore(env, order) {
  if (env.ORDER_KV) {
    await env.ORDER_KV.put(`order:${order.id}`, JSON.stringify(order));
  }
}

