// worker-order/wrangler.toml
// ============================================
/*
name = "order-worker"
main = "src/index.js"
compatibility_date = "2024-01-01"

[[kv_namespaces]]
binding = "ORDER_KV"
id = "your-order-kv-namespace-id"

[[services]]
binding = "AUTH_SERVICE"
service = "auth-worker"

[[services]]
binding = "PRODUCT_SERVICE"
service = "product-worker"

[[services]]
binding = "NOTIFICATION_SERVICE"
service = "notification-worker"
*/

// ============================================
// worker-notification/src/index.js
// Internal Notification Service Worker
// ============================================

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname.replace("/notifications", "") || "/";
    const method = request.method;
    const requestId = request.headers.get("X-Request-Id") || "direct-call";

    const router = new Router();

    router.post("/event", async (req) => {
      const event = await req.json();

      // Log the event
      const logEntry = {
        id: crypto.randomUUID(),
        ...event,
        requestId,
        receivedAt: new Date().toISOString(),
        processed: false,
      };

      // Store event in KV for audit trail
      if (env.NOTIFICATION_KV) {
        await env.NOTIFICATION_KV.put(`event:${logEntry.id}`, JSON.stringify(logEntry), {
          expirationTtl: 86400 * 30, // 30 days
        });

        // Maintain event index by type
        const indexKey = `index:${event.type}`;
        const existingIndex = (await env.NOTIFICATION_KV.get(indexKey, "json")) || [];
        existingIndex.push({ id: logEntry.id, timestamp: logEntry.receivedAt });
        // Keep last 1000 events per type
        if (existingIndex.length > 1000) existingIndex.shift();
        await env.NOTIFICATION_KV.put(indexKey, JSON.stringify(existingIndex));
      }

      // Process event based on type
      const processed = await processEvent(event, env, ctx);

      logEntry.processed = true;
      logEntry.processedAt = new Date().toISOString();
      logEntry.processingResult = processed;

      if (env.NOTIFICATION_KV) {
        await env.NOTIFICATION_KV.put(`event:${logEntry.id}`, JSON.stringify(logEntry), {
          expirationTtl: 86400 * 30,
        });
      }

      return jsonResponse({ received: true, eventId: logEntry.id, requestId });
    });

    router.post("/send", async (req) => {
      const { channel, recipient, subject, body: messageBody, data } = await req.json();

      if (!channel || !recipient) {
        return jsonResponse({ error: "Channel and recipient are required" }, 400);
      }

      const notification = {
        id: crypto.randomUUID(),
        channel,
        recipient,
        subject: subject || "",
        body: messageBody || "",
        data: data || {},
        status: "queued",
        createdAt: new Date().toISOString(),
      };

      // In production, this would integrate with email/SMS/push APIs
      // For now, store and simulate sending
      notification.status = "sent";
      notification.sentAt = new Date().toISOString();

      if (env.NOTIFICATION_KV) {
        await env.NOTIFICATION_KV.put(`notification:${notification.id}`, JSON.stringify(notification), {
          expirationTtl: 86400 * 7,
        });
      }

      console.log(`[NOTIFICATION] ${channel} -> ${recipient}: ${subject}`);

      return jsonResponse({ notification, requestId });
    });

    router.get("/events", async (req) => {
      const searchParams = new URL(req.url).searchParams;
      const type = searchParams.get("type");
      const limit = parseInt(searchParams.get("limit") || "50");

      if (!env.NOTIFICATION_KV) {
        return jsonResponse({ events: [], total: 0 });
      }

      let events = [];
      if (type) {
        const index = (await env.NOTIFICATION_KV.get(`index:${type}`, "json")) || [];
        const recentIds = index.slice(-limit);
        events = await Promise.all(recentIds.map((entry) => env.NOTIFICATION_KV.get(`event:${entry.id}`, "json")));
        events = events.filter(Boolean);
      } else {
        const list = await env.NOTIFICATION_KV.list({ prefix: "event:", limit });
        events = await Promise.all(list.keys.map((key) => env.NOTIFICATION_KV.get(key.name, "json")));
        events = events.filter(Boolean);
      }

      return jsonResponse({ events, total: events.length, requestId });
    });

    router.get("/events/:id", async (req, params) => {
      if (!env.NOTIFICATION_KV) {
        return jsonResponse({ error: "Event not found" }, 404);
      }
      const event = await env.NOTIFICATION_KV.get(`event:${params.id}`, "json");
      if (!event) return jsonResponse({ error: "Event not found" }, 404);
      return jsonResponse({ event, requestId });
    });

    router.get("/health", () => {
      return jsonResponse({
        service: "notification",
        status: "healthy",
        timestamp: new Date().toISOString(),
        channels: ["email", "webhook", "log"],
      });
    });

    return router.handle(method, path, request);
  },
};

async function processEvent(event, env, ctx) {
  const handlers = {
    "user.login": async (evt) => {
      console.log(`[EVENT] User login: ${evt.email} from ${evt.country}`);
      return { action: "logged", email: evt.email };
    },
    "user.created": async (evt) => {
      console.log(`[EVENT] New user created: ${evt.email}`);
      // Could send welcome email
      return { action: "welcome_queued", userId: evt.userId };
    },
    "order.created": async (evt) => {
      console.log(`[EVENT] Order created: ${evt.orderId} for ${evt.email}, total: $${evt.total}`);
      return { action: "confirmation_queued", orderId: evt.orderId };
    },
    "order.status_changed": async (evt) => {
      console.log(`[EVENT] Order ${evt.orderId} status: ${evt.previousStatus} -> ${evt.newStatus}`);
      return { action: "status_notification_queued", orderId: evt.orderId };
    },
    "product.out_of_stock": async (evt) => {
      console.log(`[EVENT] Product out of stock: ${evt.productName} (${evt.productId})`);
      return { action: "stock_alert_queued", productId: evt.productId };
    },
  };

  const handler = handlers[event.type];
  if (handler) {
    return handler(event);
  }

  console.log(`[EVENT] Unhandled event type: ${event.type}`, JSON.stringify(event));
  return { action: "unhandled", type: event.type };
}

// ============================================
// worker-notification/wrangler.toml
// ============================================
/*
name = "notification-worker"
main = "src/index.js"
compatibility_date = "2024-01-01"

[[kv_namespaces]]
binding = "NOTIFICATION_KV"
id = "your-notification-kv-namespace-id"

# This worker is a leaf service - no outbound service bindings needed
# But could add them if needed for email APIs etc.
*/

// ============================================
// Shared Router class (used by all workers)
// In production, this would be in a shared package
// ============================================

class Router {
  constructor() {
    this.routes = [];
  }

  get(path, handler) {
    this.routes.push({ method: "GET", path, handler });
  }

  post(path, handler) {
    this.routes.push({ method: "POST", path, handler });
  }

  put(path, handler) {
    this.routes.push({ method: "PUT", path, handler });
  }

  delete(path, handler) {
    this.routes.push({ method: "DELETE", path, handler });
  }

  patch(path, handler) {
    this.routes.push({ method: "PATCH", path, handler });
  }

  matchRoute(method, path) {
    for (const route of this.routes) {
      if (route.method !== method) continue;

      const routeParts = route.path.split("/").filter(Boolean);
      const pathParts = path.split("/").filter(Boolean);

      if (routeParts.length !== pathParts.length) continue;

      const params = {};
      let match = true;

      for (let i = 0; i < routeParts.length; i++) {
        if (routeParts[i].startsWith(":")) {
          params[routeParts[i].slice(1)] = pathParts[i];
        } else if (routeParts[i] !== pathParts[i]) {
          match = false;
          break;
        }
      }

      if (match) {
        return { handler: route.handler, params };
      }
    }
    return null;
  }

  async handle(method, path, request) {
    // Normalize path
    const normalizedPath = path === "" ? "/" : path;

    const matched = this.matchRoute(method, normalizedPath);

    if (matched) {
      try {
        return await matched.handler(request, matched.params);
      } catch (error) {
        console.error(`Route handler error: ${error.message}`, error.stack);
        return jsonResponse(
          {
            error: "Internal Service Error",
            message: error.message,
          },
          500
        );
      }
    }

    return jsonResponse(
      {
        error: "Not Found",
        message: `No handler for ${method} ${normalizedPath}`,
      },
      404
    );
  }
}

// ============================================
// Shared utility function
// ============================================

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      "Content-Type": "application/json",
    },
  });
}

